// Decision: Is this extension in-core or side-by-side?
// Use this framework for every extension request

if (extension.requires_modification_of_standard_objects) {
  // Side-by-side on BTP — extension does not belong in the core
  return 'Build as RAP/CAP service on BTP';
} else if (extension.is_simple_field_addition) {
  // Key user extensibility (in-app)
  return 'Use in-app extensibility in S/4HANA';
} else if (extension.uses_released_api) {
  // Side-by-side with clean core compliance
  return 'Build on BTP with released API';
} else {
  // Blocked — must find a released API or redesign
  return 'Extension blocked: no released API available. Find alternative approach.';
}
